const fmt     = (n) => new Intl.NumberFormat("en-US",{style:"currency",currency:"USD"}).format(n||0);
const fmtDate = (d) => { if(!d) return "—"; try { return new Date(d).toLocaleDateString("es-ES",{day:"2-digit",month:"short",year:"numeric"}); } catch { return d; } };
const pctFmt  = (n) => `${Number(n).toFixed(2).replace(/\.?0+$/,"")}%`;

// ─── Notion API via Vercel proxy (avoids CORS) ───────────────────────────────
// Uses query param ?path= to avoid Vercel routing conflicts
async function notionCall(method, path, body) {
  const res = await fetch(`/api/notion?path=${encodeURIComponent(path)}`, {
    method,
    headers: { "Content-Type": "application/json" },
    body: body ? JSON.stringify(body) : undefined,
  });
  if (!res.ok) {
    const txt = await res.text();
    throw new Error(`Notion ${res.status}: ${txt}`);
  }
  return res.json();
}

async function notionQuery(dbId, filter, cursor) {
  const body = { page_size: 100 };
  if (filter) body.filter = filter;
  if (cursor) body.start_cursor = cursor;
  return notionCall("POST", `databases/${dbId}/query`, body);
}

async function notionPatch(pageId, props) {
  return notionCall("PATCH", `pages/${pageId}`, { properties: props });
}

async function notionCreate(dbId, props) {
  return notionCall("POST", "pages", {
    parent: { database_id: dbId },
    properties: props,
  });
}

// Parse a Notion page into our entry format
function parseNotionPage(page, category) {
  const p = page.properties || {};
  const getTitle  = (k) => p[k]?.title?.[0]?.plain_text || "";
  const getNumber = (k) => p[k]?.number || 0;
  const getText   = (k) => p[k]?.rich_text?.[0]?.plain_text || "";
  const getSelect = (k) => p[k]?.select?.name || p[k]?.status?.name || "";
  const getDate   = (k) => p[k]?.date?.start || "";

  return {
    id: page.id,
    budget: getTitle("Budget") || getTitle("Name"),
    amount: getNumber("Amount"),
    businessUnit: getSelect("Business Unit"),
    expectedDate: getDate("Expected Date"),
    notes: getText("Notes") || getText("details"),
    status: getSelect("status"),
    category,
  };
}

// Build Notion properties object for create/update
function buildNotionProps(entry) {
  const props = {};
  if (entry.budget !== undefined)
    props["Budget"] = { title: [{ text: { content: entry.budget } }] };
  if (entry.amount !== undefined)
    props["Amount"] = { number: entry.amount };
  if (entry.status !== undefined)
    props["status"] = { status: { name: entry.status } };
  if (entry.notes !== undefined)
    props["Notes"] = { rich_text: [{ text: { content: entry.notes } }] };
  if (entry.businessUnit)
    props["Business Unit"] = { select: { name: entry.businessUnit } };
  if (entry.expectedDate)
    props["Expected Date"] = { date: { start: entry.expectedDate } };
  return props;
}

// Load all entries from all 4 databases
async function loadAllEntries() {
  const cats = Object.entries(NOTION_DATABASES);
  const allEntries = [];
  for (const [cat, db] of cats) {
    try {
      let hasMore = true, cursor = undefined;
      while (hasMore) {
        const data = await notionQuery(db.id, null, cursor);
        if (data.results) {
          data.results.forEach(p => allEntries.push(parseNotionPage(p, cat)));
        }
        hasMore = data.has_more || false;
        cursor = data.next_cursor;
      }
    } catch(e) { console.error("Error loading", cat, e); }
  }
  return allEntries;
}

// ─── UI Primitives ─────────────────────────────────────────────────────────
const iBase = {width:"100%",background:"#111",border:"1px solid #2a2a2a",color:"#fff",padding:"10px 14px",borderRadius:0,fontSize:13,outline:"none",fontFamily:"inherit",letterSpacing:"0.03em"};
function Input({label,...p}){return(
  <div>
    {label&&<label style={{fontSize:9,color:"#555",display:"block",marginBottom:6,textTransform:"uppercase",letterSpacing:"0.15em"}}>{label}</label>}
    <input {...p} style={{...iBase,...p.style}}/>
  </div>
);}
function Select({label,children,...p}){return(
  <div>
    {label&&<label style={{fontSize:9,color:"#555",display:"block",marginBottom:6,textTransform:"uppercase",letterSpacing:"0.15em"}}>{label}</label>}
    <select {...p} style={{...iBase,...p.style}}>{children}</select>
  </div>
);}
function Btn({children,variant="ghost",...p}){
  const s={
    primary:{background:"#fff",border:"none",color:"#000",fontWeight:700,letterSpacing:"0.1em"},
    ghost:  {background:"transparent",border:"1px solid #2a2a2a",color:"#666",letterSpacing:"0.05em"},
    danger: {background:"transparent",border:"1px solid #444",color:"#888",letterSpacing:"0.05em"},
  };
  return <button {...p} style={{padding:"10px 20px",borderRadius:0,fontSize:11,fontFamily:"inherit",cursor:"pointer",textTransform:"uppercase",...s[variant],...p.style}}>{children}</button>;
}
function Modal({open,onClose,title,children}){
  if(!open) return null;
  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.92)",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div className="cs-fadein" style={{background:"#0a0a0a",border:"1px solid #222",padding:28,width:"100%",maxWidth:440,maxHeight:"90vh",overflowY:"auto"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24}}>
          <div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:22,color:"#fff",letterSpacing:"0.08em"}}>{title}</div>
          <button onClick={onClose} style={{background:"transparent",border:"none",color:"#444",fontSize:22,cursor:"pointer",lineHeight:1}}>×</button>
        </div>
        {children}
      </div>
    </div>
  );
}

