// LOGIN
// ═══════════════════════════════════════════════════════════════════════════
function LoginScreen({onLogin}){
  const [pwd,setPwd]=useState(""); const [err,setErr]=useState(false); const [show,setShow]=useState(false);
  const attempt=()=>{ if(pwd===APP_PASSWORD){onLogin();} else{setErr(true);setPwd("");setTimeout(()=>setErr(false),2000);} };
  return(
    <div style={{minHeight:"100vh",background:"#000",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:24}}>
      <div className="cs-fadein" style={{width:"100%",maxWidth:360}}>
        <div style={{textAlign:"center",marginBottom:48}}>
          <img src={LOGO_B64} alt="Cariló Studios" style={{width:200,marginBottom:0,filter:"invert(0)"}}/>
        </div>
        <div style={{borderTop:"1px solid #1a1a1a",paddingTop:32}}>
          <div style={{fontSize:9,color:"#333",textTransform:"uppercase",letterSpacing:"0.2em",textAlign:"center",marginBottom:24}}>Finance Dashboard — Acceso Privado</div>
          <div style={{marginBottom:16}}>
            <label style={{fontSize:9,color:"#444",display:"block",marginBottom:8,textTransform:"uppercase",letterSpacing:"0.15em"}}>Contraseña</label>
            <div style={{position:"relative"}}>
              <input type={show?"text":"password"} placeholder="••••••••••" value={pwd}
                onChange={e=>{setPwd(e.target.value);setErr(false);}}
                onKeyDown={e=>e.key==="Enter"&&attempt()}
                style={{width:"100%",background:"#0a0a0a",border:`1px solid ${err?"#555":"#1a1a1a"}`,color:"#fff",padding:"13px 44px 13px 16px",fontSize:14,outline:"none",fontFamily:"inherit",letterSpacing:"0.1em",boxSizing:"border-box",transition:"border-color 0.2s"}}/>
              <button onClick={()=>setShow(s=>!s)} style={{position:"absolute",right:14,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",color:"#333",cursor:"pointer",fontSize:13}}>
                {show?"●○":"○●"}
              </button>
            </div>
            {err&&<div style={{fontSize:10,color:"#666",marginTop:8,letterSpacing:"0.05em"}}>Contraseña incorrecta</div>}
          </div>
          <button onClick={attempt} style={{width:"100%",background:"#fff",border:"none",color:"#000",padding:"13px",fontSize:11,fontWeight:700,fontFamily:"inherit",cursor:"pointer",textTransform:"uppercase",letterSpacing:"0.15em"}}>
            Ingresar
          </button>
        </div>
      </div>
    </div>
  );
}

